var success = StelSkyCultureMgr.setCurrentSkyCultureNameI18('Chinese');
if(success) {
    core.debug('Changed to Chinese sky culture');
} else {
    core.debug('Failed to change sky culture');
}

StelSkyCultureMgr.setCurrentSkyCultureID('egyptian');
core.debug('Egyptian sky culture activated');

StelSkyCultureMgr.setCurrentSkyCultureID('modern');
core.debug('Modern IAU sky culture activated');

core.debug('Reloading current sky culture...');
StelSkyCultureMgr.reloadSkyCulture();
core.debug('Sky culture reloaded');

var boundaryType = StelSkyCultureMgr.getCurrentSkyCultureBoundariesType();
if(boundaryType === -1) {
    core.debug('No constellation boundaries defined');
} else if(boundaryType === 0) {
    core.debug('Using IAU constellation boundaries');
} else {
    core.debug('Using custom sky culture boundaries');
}

var classification = StelSkyCultureMgr.getCurrentSkyCultureClassificationIdx();
var types = ['Incomplete', 'Personal', 'Traditional', 'Ethnographic', 'Historical', 'Single source', 'Comparative'];
core.debug('Sky culture classification: ' + types[classification]);

var htmlDesc = StelSkyCultureMgr.getCurrentSkyCultureHtmlClassification();
core.debug('Classification HTML: ' + htmlDesc);
// This can be displayed in a GUI dialog or info panel

var fullDescription = StelSkyCultureMgr.getCurrentSkyCultureHtmlDescription();
core.debug('Full sky culture description retrieved : ' +  fullDescription);
// Can be displayed in a dialog or info panel

var narration = StelSkyCultureMgr.getCurrentSkyCultureNarration();
core.say(narration);
core.debug('Narration text: ' + narration);

var success = StelSkyCultureMgr.setDefaultSkyCultureID('modern');
if(success) {
    core.debug('Default sky culture set to modern');
    StelApp.immediateSave();
}

var cultures = StelSkyCultureMgr.getSkyCultureListEnglish();
core.debug('Available sky cultures: ' + cultures.join(', '));
core.debug('Total cultures: ' + cultures.length);

var i18nCultures = StelSkyCultureMgr.getSkyCultureListI18();
core.debug('Localized culture names: ' + i18nCultures.join(', '));
for(var i=0; i<i18nCultures.length; i++) {
    core.debug((i+1) + ': ' + i18nCultures[i]);
}

var regionMap = StelSkyCultureMgr.getSkyCultureRegionMapI18();
core.debug('Region map size: ' + Object.keys(regionMap).length);
// This returns a JavaScript object with culture names as keys and regions as values

var timeMap = StelSkyCultureMgr.getSkyCultureTimeLimitMapI18();
core.debug('Time limit map retrieved');
// For historical cultures: beginTime and endTime years

var ids = StelSkyCultureMgr.getSkyCultureListIDs();
core.debug('Available culture IDs: ' + ids.join(', '));
for(var i=0; i<ids.length; i++) {
    core.debug('ID ' + i + ': ' + ids[i]);
}

var cultureMap = StelSkyCultureMgr.getDirToI18Map();
core.debug('Culture ID to name map retrieved');
