var style = StelSkyCultureMgr.getScreenLabelStyle();
core.debug('Current screen label style code: ' + style);

// Set a different style later
if(style !== 64) {
    StelSkyCultureMgr.setScreenLabelStyle(64); // Show only native names
    core.debug('Switched to native-only labels');
}

if(ConstellationMgr.hasZodiac()) {
    var zodiacStyle = StelSkyCultureMgr.getZodiacLabelStyle();
    core.debug('Zodiac label style code: ' + zodiacStyle);

    // Switch to native zodiac names
    StelSkyCultureMgr.setZodiacLabelStyle(64);
    ConstellationMgr.setFlagZodiac(true);
}

if(ConstellationMgr.hasLunarSystem()) {
    var lunarStyle = StelSkyCultureMgr.getLunarSystemLabelStyle();
    core.debug('Lunar system label style code: ' + lunarStyle);

    // Show both native and translated names
    StelSkyCultureMgr.setLunarSystemLabelStyle(72); // Native + Translated
    ConstellationMgr.setFlagLunarSystem(true);
