// Show only native names
StelSkyCultureMgr.setScreenLabelStyle(64);

// Show native names with translations and IPA pronunciation
StelSkyCultureMgr.setScreenLabelStyle(64 + 8 + 4); // or 76

// Show only modern (IAU) names
StelSkyCultureMgr.setScreenLabelStyle(1);

// Get current style first, then modify
var current = StelSkyCultureMgr.getScreenLabelStyle();
StelSkyCultureMgr.setScreenLabelStyle(current | 64); // Add native names to current style

// Show translated names only in info panel
StelSkyCultureMgr.setInfoLabelStyle(8);

// Show native names with IPA pronunciation
StelSkyCultureMgr.setInfoLabelStyle(64 + 4); // or 68

// Show everything possible
StelSkyCultureMgr.setInfoLabelStyle(64 + 32 + 16 + 8 + 4 + 2 + 1); // or 127

if(ConstellationMgr.hasZodiac()) {
    // Show native zodiac names
    StelSkyCultureMgr.setZodiacLabelStyle(64);

    // Show translated names only
    StelSkyCultureMgr.setZodiacLabelStyle(8);

    // Show zodiac with zodiac artwork
    ConstellationMgr.setFlagZodiac(true);
}

if(ConstellationMgr.hasLunarSystem()) {
    // Show native lunar mansion names
    StelSkyCultureMgr.setLunarSystemLabelStyle(64);

    // Show both native and translated
    StelSkyCultureMgr.setLunarSystemLabelStyle(64 + 8); // or 72

    // Display lunar system
    ConstellationMgr.setFlagLunarSystem(true);
}

